-- CPT/HCPCS RVU 2025 Seed Data
-- Source: CMS 2025 Physician Fee Schedule Relative Value File (RVU25A January Release)
-- Descriptions are CMS-authored short descriptions (public domain)

CREATE TABLE IF NOT EXISTS cpt_codes (
  id VARCHAR PRIMARY KEY DEFAULT gen_random_uuid()::text,
  code VARCHAR(6) UNIQUE NOT NULL,
  description TEXT NOT NULL,
  work_rvu DECIMAL(8,2),
  unit_type VARCHAR DEFAULT 'quantity',
  is_active BOOLEAN DEFAULT true
);

